/// almide-kernel embedded as an inlinable `mod almide_kernel`, dropped into the
/// runtime source wherever the `matrix` module is used (see emit_runtime_crate).
pub const ALMIDE_KERNEL_INLINE: &str = "#[allow(dead_code, unused_imports, unused_variables, unused_parens, unused_mut, non_snake_case, clippy::all)]\nmod almide_kernel {\npub mod gelu {\n//! gelu — activation: `0.5·x·(1 + tanh(K·(x + 0.044715·x³)))`, K=√(2/π).\n//! tanh is the autovec wall; `tanh(y) = 1 - 2/(exp(2y)+1)` reuses the shared SIMD\n//! fast-exp. within-tolerance (exp approx). The芋づる: one fast-exp, every exp/tanh\n//! op falls.\n\n#[cfg(target_arch = \"x86_64\")]\nuse super::silu::exp_pd;\n\nconst K: f64 = 0.7978845608028654; // sqrt(2/pi)\n\npub fn gelu_naive(data: &[f64], out: &mut [f64]) {\n    for i in 0..data.len() {\n        let x = data[i];\n        let inner = K * (x + 0.044715 * x * x * x);\n        out[i] = 0.5 * x * (1.0 + inner.tanh());\n    }\n}\n\n#[cfg(target_arch = \"x86_64\")]\n#[target_feature(enable = \"avx2,fma\")]\nunsafe fn gelu_avx(data: &[f64], out: &mut [f64]) {\n    use std::arch::x86_64::*;\n    let k = _mm256_set1_pd(K);\n    let c = _mm256_set1_pd(0.044715);\n    let half = _mm256_set1_pd(0.5);\n    let one = _mm256_set1_pd(1.0);\n    let two = _mm256_set1_pd(2.0);\n    let n = data.len();\n    let chunks = n / 4;\n    for ci in 0..chunks {\n        let off = ci * 4;\n        let x = _mm256_loadu_pd(data.as_ptr().add(off));\n        let x3 = _mm256_mul_pd(_mm256_mul_pd(x, x), x);\n        // inner = K*(x + 0.044715*x3)\n        let inner = _mm256_mul_pd(k, _mm256_fmadd_pd(c, x3, x));\n        // tanh(inner) = 1 - 2/(exp(2*inner)+1)\n        let e = exp_pd(_mm256_mul_pd(two, inner));\n        let t = _mm256_sub_pd(one, _mm256_div_pd(two, _mm256_add_pd(e, one)));\n        // 0.5*x*(1+t)\n        let r = _mm256_mul_pd(_mm256_mul_pd(half, x), _mm256_add_pd(one, t));\n        _mm256_storeu_pd(out.as_mut_ptr().add(off), r);\n    }\n    for i in (chunks * 4)..n {\n        let x = data[i];\n        let inner = K * (x + 0.044715 * x * x * x);\n        out[i] = 0.5 * x * (1.0 + inner.tanh());\n    }\n}\n\n#[cfg(all(target_arch = \"wasm32\", target_feature = \"simd128\"))]\nfn gelu_wasm(data: &[f64], out: &mut [f64]) {\n    use super::silu::exp_pd_wasm;\n    use std::arch::wasm32::*;\n    let k = f64x2_splat(K);\n    let c = f64x2_splat(0.044715);\n    let half = f64x2_splat(0.5);\n    let one = f64x2_splat(1.0);\n    let two = f64x2_splat(2.0);\n    let n = data.len();\n    let chunks = n / 2;\n    for ci in 0..chunks {\n        let off = ci * 2;\n        let x = unsafe { v128_load(data.as_ptr().add(off) as *const v128) };\n        let x3 = f64x2_mul(f64x2_mul(x, x), x);\n        let inner = f64x2_mul(k, f64x2_add(x, f64x2_mul(c, x3)));\n        let e = exp_pd_wasm(f64x2_mul(two, inner));\n        let t = f64x2_sub(one, f64x2_div(two, f64x2_add(e, one)));\n        let r = f64x2_mul(f64x2_mul(half, x), f64x2_add(one, t));\n        unsafe { v128_store(out.as_mut_ptr().add(off) as *mut v128, r) };\n    }\n    for i in (chunks * 2)..n {\n        let x = data[i];\n        let inner = K * (x + 0.044715 * x * x * x);\n        out[i] = 0.5 * x * (1.0 + inner.tanh());\n    }\n}\n\n#[cfg(target_arch = \"aarch64\")]\n#[target_feature(enable = \"neon\")]\nunsafe fn gelu_neon(data: &[f64], out: &mut [f64]) {\n    use super::silu::exp_pd_neon;\n    use std::arch::aarch64::*;\n    let k = vdupq_n_f64(K);\n    let c = vdupq_n_f64(0.044715);\n    let half = vdupq_n_f64(0.5);\n    let one = vdupq_n_f64(1.0);\n    let two = vdupq_n_f64(2.0);\n    let n = data.len();\n    let chunks = n / 2;\n    for ci in 0..chunks {\n        let off = ci * 2;\n        let x = vld1q_f64(data.as_ptr().add(off));\n        let x3 = vmulq_f64(vmulq_f64(x, x), x);\n        let inner = vmulq_f64(k, vaddq_f64(x, vmulq_f64(c, x3)));\n        let e = exp_pd_neon(vmulq_f64(two, inner));\n        let t = vsubq_f64(one, vdivq_f64(two, vaddq_f64(e, one)));\n        let r = vmulq_f64(vmulq_f64(half, x), vaddq_f64(one, t));\n        vst1q_f64(out.as_mut_ptr().add(off), r);\n    }\n    for i in (chunks * 2)..n {\n        let x = data[i];\n        let inner = K * (x + 0.044715 * x * x * x);\n        out[i] = 0.5 * x * (1.0 + inner.tanh());\n    }\n}\n\npub fn gelu(data: &[f64], out: &mut [f64]) {\n    assert_eq!(data.len(), out.len());\n    #[cfg(target_arch = \"x86_64\")]\n    {\n        if is_x86_feature_detected!(\"avx2\") && is_x86_feature_detected!(\"fma\") {\n            return unsafe { gelu_avx(data, out) };\n        }\n    }\n    #[cfg(target_arch = \"aarch64\")]\n    {\n        if std::arch::is_aarch64_feature_detected!(\"neon\") {\n            return unsafe { gelu_neon(data, out) };\n        }\n    }\n    #[cfg(all(target_arch = \"wasm32\", target_feature = \"simd128\"))]\n    {\n        return gelu_wasm(data, out);\n    }\n    gelu_naive(data, out);\n}\n\n\n}\npub mod matmul {\n//! Dense matmul `C = A·B` (m×k · k×n, row-major). SIMD inner product: transpose\n//! B once so each column becomes a contiguous row, then a SIMD dot per (i,j).\n//!\n//! This beats Almide's tiled-*scalar* mul by vectorizing the inner product. BLAS\n//! lives here too — register-tiled micro-kernels (6x16, packing, prefetch) are\n//! the ceiling and we don't reach it; this is the SIMD-dot rung, enough to pass\n//! a scalar inner loop. Used for sdpa's QKᵀ and weights·V.\n\n/// Naive tiled-scalar reference (≈ Almide's mul).\npub fn matmul_naive(a: &[f64], m: usize, k: usize, b: &[f64], n: usize, out: &mut [f64]) {\n    for x in out.iter_mut() {\n        *x = 0.0;\n    }\n    const T: usize = 32;\n    let mut i0 = 0;\n    while i0 < m {\n        let i1 = (i0 + T).min(m);\n        let mut k0 = 0;\n        while k0 < k {\n            let k1 = (k0 + T).min(k);\n            let mut j0 = 0;\n            while j0 < n {\n                let j1 = (j0 + T).min(n);\n                for i in i0..i1 {\n                    for kk in k0..k1 {\n                        let aik = a[i * k + kk];\n                        for j in j0..j1 {\n                            out[i * n + j] += aik * b[kk * n + j];\n                        }\n                    }\n                }\n                j0 += T;\n            }\n            k0 += T;\n        }\n        i0 += T;\n    }\n}\n\n#[cfg(target_arch = \"x86_64\")]\n#[target_feature(enable = \"avx2,fma\")]\n#[allow(dead_code)]\nunsafe fn matmul_avx(a: &[f64], m: usize, k: usize, b: &[f64], n: usize, out: &mut [f64]) {\n    use std::arch::x86_64::*;\n    // transpose B → bt (n×k), columns become contiguous rows\n    let mut bt = vec![0.0f64; n * k];\n    for kk in 0..k {\n        let brow = &b[kk * n..kk * n + n];\n        for j in 0..n {\n            bt[j * k + kk] = brow[j];\n        }\n    }\n    let chunks = k / 4;\n    for i in 0..m {\n        let ai = &a[i * k..i * k + k];\n        for j in 0..n {\n            let bj = &bt[j * k..j * k + k];\n            let mut acc = _mm256_setzero_pd();\n            for c in 0..chunks {\n                let av = _mm256_loadu_pd(ai.as_ptr().add(c * 4));\n                let bv = _mm256_loadu_pd(bj.as_ptr().add(c * 4));\n                acc = _mm256_fmadd_pd(av, bv, acc);\n            }\n            let hi = _mm256_extractf128_pd(acc, 1);\n            let lo = _mm256_castpd256_pd128(acc);\n            let s = _mm_add_pd(lo, hi);\n            let s = _mm_add_sd(s, _mm_unpackhi_pd(s, s));\n            let mut sum = _mm_cvtsd_f64(s);\n            for kk in (chunks * 4)..k {\n                sum += ai[kk] * bj[kk];\n            }\n            out[i * n + j] = sum;\n        }\n    }\n}\n\n/// Register-tiled matmul: 4×4 micro-kernel. The 4×4 block of C lives in 4 ymm\n/// accumulators; the k-loop loads one B row (contiguous, 4 doubles) and fma's it\n/// into all 4 C rows (B reuse), broadcasting one A element per row. This is BLAS's\n/// register-blocking core — C stays in registers across k, memory traffic is just\n/// A column + B row. Ragged edges (m%4, n%4) fall back to scalar.\n#[cfg(target_arch = \"x86_64\")]\n#[target_feature(enable = \"avx2,fma\")]\nunsafe fn matmul_register_tiled(a: &[f64], m: usize, k: usize, b: &[f64], n: usize, out: &mut [f64]) {\n    use std::arch::x86_64::*;\n    let mt = m / 4 * 4;\n    let nt = n / 4 * 4;\n    let mut i0 = 0;\n    while i0 < mt {\n        let mut j0 = 0;\n        while j0 < nt {\n            let mut c0 = _mm256_setzero_pd();\n            let mut c1 = _mm256_setzero_pd();\n            let mut c2 = _mm256_setzero_pd();\n            let mut c3 = _mm256_setzero_pd();\n            for kk in 0..k {\n                let brow = _mm256_loadu_pd(b.as_ptr().add(kk * n + j0));\n                c0 = _mm256_fmadd_pd(_mm256_set1_pd(*a.get_unchecked((i0) * k + kk)), brow, c0);\n                c1 = _mm256_fmadd_pd(_mm256_set1_pd(*a.get_unchecked((i0 + 1) * k + kk)), brow, c1);\n                c2 = _mm256_fmadd_pd(_mm256_set1_pd(*a.get_unchecked((i0 + 2) * k + kk)), brow, c2);\n                c3 = _mm256_fmadd_pd(_mm256_set1_pd(*a.get_unchecked((i0 + 3) * k + kk)), brow, c3);\n            }\n            _mm256_storeu_pd(out.as_mut_ptr().add((i0) * n + j0), c0);\n            _mm256_storeu_pd(out.as_mut_ptr().add((i0 + 1) * n + j0), c1);\n            _mm256_storeu_pd(out.as_mut_ptr().add((i0 + 2) * n + j0), c2);\n            _mm256_storeu_pd(out.as_mut_ptr().add((i0 + 3) * n + j0), c3);\n            j0 += 4;\n        }\n        i0 += 4;\n    }\n    // ragged edges: any (i,j) not in the 4×4-tiled region\n    for i in 0..m {\n        for j in 0..n {\n            if i >= mt || j >= nt {\n                let mut s = 0.0;\n                for kk in 0..k {\n                    s += a[i * k + kk] * b[kk * n + j];\n                }\n                out[i * n + j] = s;\n            }\n        }\n    }\n}\n\n/// Per-target dispatch.\npub fn matmul(a: &[f64], m: usize, k: usize, b: &[f64], n: usize, out: &mut [f64]) {\n    #[cfg(target_arch = \"x86_64\")]\n    {\n        if is_x86_feature_detected!(\"avx2\") && is_x86_feature_detected!(\"fma\") {\n            return unsafe { matmul_register_tiled(a, m, k, b, n, out) };\n        }\n    }\n    matmul_naive(a, m, k, b, n, out);\n}\n\n\n}\npub mod q1_0 {\n//! Q1_0 block dot — the inner kernel of 1-bit quantized matmul.\n//!\n//! This is where almide-kernel beats Rust hardest: the work is \"unpack a packed\n//! sign bit per element, then a signed sum\". rustc can't autovectorize it (bit\n//! addressing is non-affine), and Almide's own `q1_0_block_dot` falls to *scalar*\n//! on x86 (its SIMD path is NEON-only). Explicit AVX2 has the floor to itself.\n//!\n//! Exo-style: algorithm (the signed-sum spec) and schedule (AVX2 bit-unpack +\n//! lane-parallel sum + horizontal reduce) separated. NOTE: this is a reduction,\n//! so the schedule reassociates the float sum — equivalence is \"within\n//! tolerance\", not bitwise. (Wyve/Exo require reassoc for float reductions;\n//! bitwise-exact is the wrong bar. transpose was data-movement → bitwise; this\n//! is a sum → reassoc. Being explicit about which bar applies is the point.)\n\n/// Algorithm: `out = (Σ_k x[k] * sign(k)) * scale`, where `sign(k) = -1` if the\n/// k-th packed bit is set, else `+1`. 128-element block; sign is 16 bytes\n/// (128 bits, LSB-first within each byte).\npub fn q1_0_dot_naive(x: &[f32; 128], sign: &[u8; 16], scale: f32) -> f32 {\n    let mut acc = 0.0f32;\n    for k in 0..128 {\n        let bit = (sign[k / 8] >> (k % 8)) & 1;\n        acc += if bit == 1 { -x[k] } else { x[k] };\n    }\n    acc * scale\n}\n\n/// Public entry: per-target SIMD schedule (AVX2 on x86, simd128 on wasm),\n/// naive algorithm as the fallback.\npub fn q1_0_dot(x: &[f32; 128], sign: &[u8; 16], scale: f32) -> f32 {\n    #[cfg(target_arch = \"x86_64\")]\n    {\n        if is_x86_feature_detected!(\"avx2\") {\n            // SAFETY: guarded by the runtime feature check.\n            return unsafe { q1_0_dot_avx2(x, sign, scale) };\n        }\n    }\n    #[cfg(all(target_arch = \"wasm32\", target_feature = \"simd128\"))]\n    {\n        return q1_0_dot_simd128(x, sign, scale);\n    }\n    #[allow(unreachable_code)]\n    q1_0_dot_naive(x, sign, scale)\n}\n\n/// Schedule (wasm simd128): the same bit-unpack as AVX2, 4-wide (v128 = f32x4).\n/// wasm has no autovec for this and Almide's wasm path is scalar — so this is\n/// where almide-kernel beats both Rust-wasm and Almide-wasm.\n#[cfg(all(target_arch = \"wasm32\", target_feature = \"simd128\"))]\npub fn q1_0_dot_simd128(x: &[f32; 128], sign: &[u8; 16], scale: f32) -> f32 {\n    use std::arch::wasm32::*;\n    let lane_bit = i32x4(1, 2, 4, 8);\n    let signbit = i32x4_splat(0x8000_0000u32 as i32);\n    let mut acc = f32x4_splat(0.0);\n    for blk in 0..32 {\n        let bit_base = blk * 4;\n        let byte = sign[bit_base / 8];\n        let nib = ((byte >> (bit_base % 8)) & 0xF) as i32;\n        let b = i32x4_splat(nib);\n        let sel = v128_and(b, lane_bit);\n        let is_set = i32x4_eq(sel, lane_bit); // all-ones where bit set\n        let flip = v128_and(is_set, signbit); // 0x80000000 where set\n        // SAFETY: blk in 0..32, blk*4 in 0..128, x has 128 elems.\n        let xv = unsafe { v128_load(x.as_ptr().add(blk * 4) as *const v128) };\n        let signed = v128_xor(xv, flip);\n        acc = f32x4_add(acc, signed);\n    }\n    let s = f32x4_extract_lane::<0>(acc)\n        + f32x4_extract_lane::<1>(acc)\n        + f32x4_extract_lane::<2>(acc)\n        + f32x4_extract_lane::<3>(acc);\n    s * scale\n}\n\n/// Schedule (AVX2): for each byte, broadcast it, select each lane's bit, turn a\n/// set bit into the float sign bit (0x80000000), XOR it onto x (flip sign), and\n/// accumulate 8-wide; then horizontally reduce. This is the bit-unpack rustc\n/// can't reach.\n/// The bit-unpack, isolated: apply 8 packed sign bits (one byte, LSB-first) to\n/// 8 lanes — lane k gets `-x` if bit k is set, else `x`. It's an XOR of the sign\n/// bit, hence value-independent. This is the part proven statically and\n/// exhaustively (256 byte values = all bit patterns); the reduction around it is\n/// the reassociated part that stays within-tolerance.\n#[cfg(target_arch = \"x86_64\")]\n#[target_feature(enable = \"avx2\")]\nunsafe fn apply_sign_avx2(x: std::arch::x86_64::__m256, byte: u8) -> std::arch::x86_64::__m256 {\n    use std::arch::x86_64::*;\n    let lane_bit = _mm256_setr_epi32(1, 2, 4, 8, 16, 32, 64, 128); // LSB-first per byte\n    let signbit = _mm256_set1_epi32(0x8000_0000u32 as i32);\n    let b = _mm256_set1_epi32(byte as i32);\n    let sel = _mm256_and_si256(b, lane_bit);\n    let is_set = _mm256_cmpeq_epi32(sel, lane_bit); // 0xFFFFFFFF where bit set\n    let flip = _mm256_and_si256(is_set, signbit); // 0x80000000 where set\n    _mm256_xor_ps(x, _mm256_castsi256_ps(flip))\n}\n\n#[cfg(target_arch = \"x86_64\")]\n#[target_feature(enable = \"avx2\")]\npub unsafe fn q1_0_dot_avx2(x: &[f32; 128], sign: &[u8; 16], scale: f32) -> f32 {\n    use std::arch::x86_64::*;\n    let mut acc = _mm256_setzero_ps();\n    for blk in 0..16 {\n        let xv = _mm256_loadu_ps(x.as_ptr().add(blk * 8));\n        let signed = apply_sign_avx2(xv, sign[blk]);\n        acc = _mm256_add_ps(acc, signed);\n    }\n    // horizontal reduce 8 -> 1\n    let lo = _mm256_castps256_ps128(acc);\n    let hi = _mm256_extractf128_ps(acc, 1);\n    let s = _mm_add_ps(lo, hi);\n    let s = _mm_hadd_ps(s, s);\n    let s = _mm_hadd_ps(s, s);\n    _mm_cvtss_f32(s) * scale\n}\n\n/// Full quantized linear — the inference hot path. `out[m,n] = Σ_k x[m,k]·W[n,k]`\n/// with W in Q1_0. x: `[m*k]` row-major f32; w_sign: `[n*blocks*16]` u8;\n/// w_scale: `[n*blocks]` f32; k a multiple of 128. Uses the per-target\n/// `q1_0_dot` schedule (AVX2 / simd128 / naive) for every block dot.\npub fn linear_q1_0(\n    x: &[f32], m: usize, k: usize,\n    w_sign: &[u8], w_scale: &[f32], n: usize,\n    out: &mut [f32],\n) {\n    let blocks = k / 128;\n    for mi in 0..m {\n        for ni in 0..n {\n            let mut acc = 0.0f32;\n            for b in 0..blocks {\n                let xb: &[f32; 128] =\n                    (&x[mi * k + b * 128..mi * k + b * 128 + 128]).try_into().unwrap();\n                let sb: &[u8; 16] = (&w_sign[(ni * blocks + b) * 16..(ni * blocks + b) * 16 + 16])\n                    .try_into()\n                    .unwrap();\n                acc += q1_0_dot(xb, sb, w_scale[ni * blocks + b]);\n            }\n            out[mi * n + ni] = acc;\n        }\n    }\n}\n\n/// Naive reference for `linear_q1_0` (scalar block dot — the Rust baseline).\npub fn linear_q1_0_naive(\n    x: &[f32], m: usize, k: usize,\n    w_sign: &[u8], w_scale: &[f32], n: usize,\n    out: &mut [f32],\n) {\n    let blocks = k / 128;\n    for mi in 0..m {\n        for ni in 0..n {\n            let mut acc = 0.0f32;\n            for b in 0..blocks {\n                let xb: &[f32; 128] =\n                    (&x[mi * k + b * 128..mi * k + b * 128 + 128]).try_into().unwrap();\n                let sb: &[u8; 16] = (&w_sign[(ni * blocks + b) * 16..(ni * blocks + b) * 16 + 16])\n                    .try_into()\n                    .unwrap();\n                acc += q1_0_dot_naive(xb, sb, w_scale[ni * blocks + b]);\n            }\n            out[mi * n + ni] = acc;\n        }\n    }\n}\n\n/// The q1_0 reduction in the EXACT order the SIMD schedule uses — this is the\n/// *specification* of the reduction order (floats are order-dependent, so the\n/// order is part of the spec, not an accident). 8 lane accumulators over the 16\n/// blocks, then the horizontal tree `(l0+l4 + l1+l5) + (l2+l6 + l3+l7)` that\n/// matches `_mm_add_ps` + two `_mm_hadd_ps`. The SIMD kernel is proven\n/// bitwise-exact to THIS (layer 1). Its distance from the idealized exact sum is\n/// bounded by `n·u·Σ|xₖ|` (n=128, u=2⁻²⁴) — layer 2, the error is *bounded*, not\n/// hoped (a reduction reassociation theorem; provable in Lean).\npub fn q1_0_dot_tree_order(x: &[f32; 128], sign: &[u8; 16], scale: f32) -> f32 {\n    let mut lanes = [0.0f32; 8];\n    for blk in 0..16 {\n        for k in 0..8 {\n            let bit = (sign[blk] >> k) & 1;\n            lanes[k] += if bit == 1 { -x[blk * 8 + k] } else { x[blk * 8 + k] };\n        }\n    }\n    // horizontal reduce in the SIMD order: lo+hi, then two hadds\n    let t0 = lanes[0] + lanes[4];\n    let t1 = lanes[1] + lanes[5];\n    let t2 = lanes[2] + lanes[6];\n    let t3 = lanes[3] + lanes[7];\n    ((t0 + t1) + (t2 + t3)) * scale\n}\n\n\n}\npub mod q1_0_packed {\n//! Q1_0 in Almide's packed, f64 layout — the ABI of\n//! `almide_rt_matrix_linear_q1_0_row_no_bias`.\n//!\n//! Each 128-element block is 18 bytes: fp16 scale (2 bytes) + 128 sign bits\n//! (16 bytes, LSB-first). x is f64. Almide's own block dot is scalar on x86\n//! (its SIMD path is NEON-only), so the AVX f64 path here beats Almide itself on\n//! native — and quantized matmul is outside BLAS entirely.\n//!\n//! Two layers of correctness, same as q1_0.rs: the sign placement is a selection\n//! (exhaustively provable), and the reduction is bitwise to a named order +\n//! bounded error. Here we differential-test AVX == naive (the reduction order\n//! matches), within tolerance for the f64 sum.\n\n/// IEEE fp16 (little-endian bytes) → f64.\npub fn fp16_to_f64(lo: u8, hi: u8) -> f64 {\n    let h = (lo as u16) | ((hi as u16) << 8);\n    let sign = (h >> 15) & 1;\n    let exp = (h >> 10) & 0x1f;\n    let mant = h & 0x3ff;\n    let val: f64 = if exp == 0 {\n        // zero / subnormal: mant * 2^-24\n        (mant as f64) * (1.0 / 16_777_216.0)\n    } else if exp == 0x1f {\n        if mant == 0 { f64::INFINITY } else { f64::NAN }\n    } else {\n        // normal: (1 + mant/1024) * 2^(exp-15)\n        (1.0 + (mant as f64) / 1024.0) * exp2i(exp as i32 - 15)\n    };\n    if sign == 1 { -val } else { val }\n}\n\n#[inline]\nfn exp2i(e: i32) -> f64 {\n    // exact power of two without powi at runtime cost concerns; e in fp16 range\n    if e >= 0 { (1u64 << e) as f64 } else { 1.0 / ((1u64 << (-e)) as f64) }\n}\n\n/// One 128-element block: `(Σ x[k]·sign(k)) · scale`, sign packed (16 bytes,\n/// LSB-first), scale already decoded. Naive reference.\npub fn q1_0_block_dot_packed_naive(x: &[f64], sign: &[u8], scale: f64) -> f64 {\n    let mut acc = 0.0f64;\n    for k in 0..128 {\n        let bit = (sign[k / 8] >> (k % 8)) & 1;\n        acc += if bit == 1 { -x[k] } else { x[k] };\n    }\n    acc * scale\n}\n\n/// AVX f64x4 block dot: apply 4 sign bits per group via XOR of the sign bit,\n/// accumulate, horizontal-reduce. The bit-unpack rustc/Almide-scalar can't reach.\n#[cfg(target_arch = \"x86_64\")]\n#[target_feature(enable = \"avx\")]\npub unsafe fn q1_0_block_dot_packed_avx(x: &[f64], sign: &[u8], scale: f64) -> f64 {\n    use std::arch::x86_64::*;\n    let negzero = f64::from_bits(0x8000_0000_0000_0000); // -0.0 = sign bit only\n    let mut acc = _mm256_setzero_pd();\n    for g in 0..32 {\n        let bit_base = g * 4;\n        let byte = sign[bit_base / 8];\n        let nib = (byte >> (bit_base % 8)) & 0xF; // 4 bits for this group of 4\n        // mask lane k = -0.0 if bit set else +0.0; XOR flips the sign of x[k]\n        let mask = _mm256_set_pd(\n            if nib & 8 != 0 { negzero } else { 0.0 },\n            if nib & 4 != 0 { negzero } else { 0.0 },\n            if nib & 2 != 0 { negzero } else { 0.0 },\n            if nib & 1 != 0 { negzero } else { 0.0 },\n        );\n        let xv = _mm256_loadu_pd(x.as_ptr().add(g * 4));\n        acc = _mm256_add_pd(acc, _mm256_xor_pd(xv, mask));\n    }\n    // horizontal reduce 4 -> 1\n    let hi = _mm256_extractf128_pd(acc, 1);\n    let lo = _mm256_castpd256_pd128(acc);\n    let s = _mm_add_pd(lo, hi);\n    let s = _mm_add_sd(s, _mm_unpackhi_pd(s, s));\n    _mm_cvtsd_f64(s) * scale\n}\n\n/// wasm simd128 block dot: f64x2, 2 sign bits per group via ±0.0 mask XOR.\n#[cfg(all(target_arch = \"wasm32\", target_feature = \"simd128\"))]\nfn q1_0_block_dot_packed_wasm(x: &[f64], sign: &[u8], scale: f64) -> f64 {\n    use std::arch::wasm32::*;\n    let negzero = f64::from_bits(0x8000_0000_0000_0000);\n    let mut acc = f64x2_splat(0.0);\n    for g in 0..64 {\n        let bit_base = g * 2;\n        let byte = sign[bit_base / 8];\n        let two = (byte >> (bit_base % 8)) & 0x3;\n        let mask = f64x2(\n            if two & 1 != 0 { negzero } else { 0.0 },\n            if two & 2 != 0 { negzero } else { 0.0 },\n        );\n        // SAFETY: g in 0..64, g*2 in 0..128, x has 128 elems.\n        let xv = unsafe { v128_load(x.as_ptr().add(g * 2) as *const v128) };\n        acc = f64x2_add(acc, v128_xor(xv, mask));\n    }\n    (f64x2_extract_lane::<0>(acc) + f64x2_extract_lane::<1>(acc)) * scale\n}\n\n/// ARM NEON block dot: f64x2, 2 sign bits per group via ±0.0 mask XOR (integer\n/// veor on the bit patterns). This is the quant hot path on Apple Silicon/mobile.\n#[cfg(target_arch = \"aarch64\")]\n#[target_feature(enable = \"neon\")]\nunsafe fn q1_0_block_dot_packed_neon(x: &[f64], sign: &[u8], scale: f64) -> f64 {\n    use std::arch::aarch64::*;\n    let negzero = f64::from_bits(0x8000_0000_0000_0000);\n    let mut acc = vdupq_n_f64(0.0);\n    for g in 0..64 {\n        let bit_base = g * 2;\n        let byte = sign[bit_base / 8];\n        let two = (byte >> (bit_base % 8)) & 0x3;\n        // mask = [lane0: bit0?−0.0:0.0, lane1: bit1?−0.0:0.0]\n        let m0 = if two & 1 != 0 { negzero } else { 0.0 };\n        let m1 = if two & 2 != 0 { negzero } else { 0.0 };\n        let mask = vsetq_lane_f64::<1>(m1, vdupq_n_f64(m0));\n        let xv = vld1q_f64(x.as_ptr().add(g * 2));\n        // XOR the sign bit (integer veor on bit patterns)\n        let signed = vreinterpretq_f64_u64(veorq_u64(\n            vreinterpretq_u64_f64(xv),\n            vreinterpretq_u64_f64(mask),\n        ));\n        acc = vaddq_f64(acc, signed);\n    }\n    (vgetq_lane_f64::<0>(acc) + vgetq_lane_f64::<1>(acc)) * scale\n}\n\n/// Block dot, per-target dispatch.\n#[inline]\npub fn q1_0_block_dot_packed(x: &[f64], sign: &[u8], scale: f64) -> f64 {\n    #[cfg(target_arch = \"x86_64\")]\n    {\n        if is_x86_feature_detected!(\"avx\") {\n            return unsafe { q1_0_block_dot_packed_avx(x, sign, scale) };\n        }\n    }\n    #[cfg(target_arch = \"aarch64\")]\n    {\n        if std::arch::is_aarch64_feature_detected!(\"neon\") {\n            return unsafe { q1_0_block_dot_packed_neon(x, sign, scale) };\n        }\n    }\n    #[cfg(all(target_arch = \"wasm32\", target_feature = \"simd128\"))]\n    {\n        return q1_0_block_dot_packed_wasm(x, sign, scale);\n    }\n    q1_0_block_dot_packed_naive(x, sign, scale)\n}\n\n/// Full quantized linear, Almide's ABI: out[i,j] = Σ_blocks dot(x[i, block],\n/// W[j, block]·scale). x: `[x_rows*n_in]` f64; w_bytes: packed Q1_0 with\n/// `w_offset`; w_rows = out cols. Writes `[x_rows*w_rows]` row-major.\npub fn linear_q1_0_packed(\n    x: &[f64], x_rows: usize, n_in: usize,\n    w_bytes: &[u8], w_offset: usize, w_rows: usize,\n    out: &mut [f64],\n) {\n    let blocks = n_in / 128;\n    for i in 0..x_rows {\n        let xi = &x[i * n_in..(i + 1) * n_in];\n        for j in 0..w_rows {\n            let row_off = w_offset + j * blocks * 18;\n            let mut sum = 0.0f64;\n            for b in 0..blocks {\n                let bs = row_off + b * 18;\n                let scale = fp16_to_f64(w_bytes[bs], w_bytes[bs + 1]);\n                let sign = &w_bytes[bs + 2..bs + 18];\n                sum += q1_0_block_dot_packed(&xi[b * 128..b * 128 + 128], sign, scale);\n            }\n            out[i * w_rows + j] = sum;\n        }\n    }\n}\n\n\n}\npub mod scale {\n//! Elementwise scale: `out[i] = a * x[i]`.\n//!\n//! Honest note (measured): elementwise is memory-bound. With `-C\n//! target-cpu=native` the autovectorized naive loop ties explicit AVX (0.99x) —\n//! rustc emits the same AVX. Default builds show explicit AVX ~1.23x *only*\n//! because autovec is capped at the SSE2 baseline target; the right fix is\n//! target-cpu, not shipping ceremony. So `scale` stays naive — almide-kernel's\n//! edge is *data-movement* (transpose: 4.23x native, autovec can't build a\n//! shuffle network), not elementwise. `scale_avx` exists only for the\n//! differential test + bench. Don't ship ceremony that doesn't pay — the same\n//! honesty that kept @stream out of Wyve's examples.\n\n/// Production: `out[i] = a * x[i]`. rustc autovectorizes this loop.\npub fn scale(a: f32, x: &[f32], out: &mut [f32]) {\n    assert_eq!(x.len(), out.len());\n    // iterator form: no bounds checks, rustc autovectorizes fully\n    for (o, &xi) in out.iter_mut().zip(x) {\n        *o = a * xi;\n    }\n}\n\n/// Explicit AVX — measurement only, differential-tested bitwise-equal to `scale`.\n#[cfg(target_arch = \"x86_64\")]\n#[target_feature(enable = \"avx\")]\npub unsafe fn scale_avx(a: f32, x: &[f32], out: &mut [f32]) {\n    use std::arch::x86_64::*;\n    let n = x.len();\n    let va = _mm256_set1_ps(a);\n    let chunks = n / 8;\n    for c in 0..chunks {\n        let off = c * 8;\n        let vx = _mm256_loadu_ps(x.as_ptr().add(off));\n        _mm256_storeu_ps(out.as_mut_ptr().add(off), _mm256_mul_ps(va, vx));\n    }\n    for i in (chunks * 8)..n {\n        out[i] = a * x[i];\n    }\n}\n\n\n}\npub mod silu {\n//! silu_mul — swiglu / FFN core: `out[i] = silu(a[i]) * b[i]`,\n//! `silu(x) = x * sigmoid(x) = x / (1 + exp(-x))`.\n//!\n//! `exp` is the autovec wall: rustc/Almide emit a scalar libm call per element,\n//! which can't vectorize. A SIMD fast-exp (range reduction + Taylor degree-6,\n//! f64 AVX) lets almide-kernel beat the scalar path. Correctness is\n//! within-tolerance (exp is approximated ~1e-7 relative, fine for an activation).\n\n/// Naive reference: scalar libm exp.\npub fn silu_mul_naive(a: &[f64], b: &[f64], out: &mut [f64]) {\n    for i in 0..a.len() {\n        let x = a[i];\n        let sig = 1.0 / (1.0 + (-x).exp());\n        out[i] = x * sig * b[i];\n    }\n}\n\n/// SIMD fast exp for f64x4: exp(x) = 2^k · exp(r), k = round(x/ln2),\n/// r = x - k·ln2 ∈ [-ln2/2, ln2/2], exp(r) by Taylor degree 6.\n/// SIMD fast exp, shared by silu/softmax/gelu — every op that hits the exp wall.\n#[cfg(target_arch = \"x86_64\")]\n#[target_feature(enable = \"avx2,fma\")]\npub(crate) unsafe fn exp_pd(x: std::arch::x86_64::__m256d) -> std::arch::x86_64::__m256d {\n    use std::arch::x86_64::*;\n    // Clamp to the bit-trick's valid range: `(k + 1023) << 52` needs the biased\n    // exponent in (0, 2046), i.e. |x| ≲ 708 (min-normal 2^-1022 .. max 2^1023).\n    // Outside it the shift WRAPS and exp returns garbage — the standard softmax\n    // mask value -1e9 corrupted whole rows (nn masked attention). Clamping to\n    // ±708 saturates to ~3e-308 / ~8e307, which every consumer (softmax weight,\n    // silu/gelu sigmoid) treats identically to 0 / inf.\n    let x = _mm256_max_pd(_mm256_set1_pd(-708.0), _mm256_min_pd(x, _mm256_set1_pd(708.0)));\n    let log2e = _mm256_set1_pd(std::f64::consts::LOG2_E);\n    let ln2 = _mm256_set1_pd(std::f64::consts::LN_2);\n    // k = round(x * log2e)\n    let kf = _mm256_round_pd::<{ _MM_FROUND_TO_NEAREST_INT | _MM_FROUND_NO_EXC }>(\n        _mm256_mul_pd(x, log2e),\n    );\n    let r = _mm256_fnmadd_pd(kf, ln2, x); // r = x - kf*ln2\n    // Taylor exp(r), Horner: ((((((1/720)r + 1/120)r + 1/24)r + 1/6)r + 1/2)r + 1)r + 1\n    let mut p = _mm256_set1_pd(1.0 / 720.0);\n    p = _mm256_fmadd_pd(p, r, _mm256_set1_pd(1.0 / 120.0));\n    p = _mm256_fmadd_pd(p, r, _mm256_set1_pd(1.0 / 24.0));\n    p = _mm256_fmadd_pd(p, r, _mm256_set1_pd(1.0 / 6.0));\n    p = _mm256_fmadd_pd(p, r, _mm256_set1_pd(0.5));\n    p = _mm256_fmadd_pd(p, r, _mm256_set1_pd(1.0));\n    p = _mm256_fmadd_pd(p, r, _mm256_set1_pd(1.0)); // exp(r)\n    // 2^k via exponent bits: ((k + 1023) << 52)\n    let ki = _mm256_cvtpd_epi32(kf); // __m128i, 4×i32\n    let k64 = _mm256_cvtepi32_epi64(ki); // 4×i64\n    let biased = _mm256_add_epi64(k64, _mm256_set1_epi64x(1023));\n    let pow2k = _mm256_castsi256_pd(_mm256_slli_epi64(biased, 52));\n    _mm256_mul_pd(p, pow2k)\n}\n\n/// SIMD silu_mul (AVX2+FMA): sigmoid via fast exp, fused with x and b.\n#[cfg(target_arch = \"x86_64\")]\n#[target_feature(enable = \"avx2,fma\")]\nunsafe fn silu_mul_avx(a: &[f64], b: &[f64], out: &mut [f64]) {\n    use std::arch::x86_64::*;\n    let n = a.len();\n    let one = _mm256_set1_pd(1.0);\n    let chunks = n / 4;\n    for c in 0..chunks {\n        let off = c * 4;\n        let x = _mm256_loadu_pd(a.as_ptr().add(off));\n        let bv = _mm256_loadu_pd(b.as_ptr().add(off));\n        // sigmoid(x) = 1/(1+exp(-x))\n        let neg = _mm256_sub_pd(_mm256_setzero_pd(), x);\n        let e = exp_pd(neg);\n        let sig = _mm256_div_pd(one, _mm256_add_pd(one, e));\n        // out = x * sig * b\n        let r = _mm256_mul_pd(_mm256_mul_pd(x, sig), bv);\n        _mm256_storeu_pd(out.as_mut_ptr().add(off), r);\n    }\n    for i in (chunks * 4)..n {\n        let x = a[i];\n        let sig = 1.0 / (1.0 + (-x).exp());\n        out[i] = x * sig * b[i];\n    }\n}\n\n/// SIMD fast exp for wasm f64x2 (same algorithm, 2-wide). Shared by silu/softmax/\n/// gelu on wasm. f64x2→i64 via i32 trunc then sign-extend (simd128 has no direct\n/// f64→i64).\n#[cfg(all(target_arch = \"wasm32\", target_feature = \"simd128\"))]\npub(crate) fn exp_pd_wasm(x: std::arch::wasm32::v128) -> std::arch::wasm32::v128 {\n    use std::arch::wasm32::*;\n    // Clamp to the bit-trick's valid range (see exp_pd): outside |x| ≲ 708 the\n    // `(k + 1023) << 52` shift wraps and returns garbage (softmax -1e9 mask).\n    let x = f64x2_max(f64x2_splat(-708.0), f64x2_min(x, f64x2_splat(708.0)));\n    let log2e = f64x2_splat(std::f64::consts::LOG2_E);\n    let ln2 = f64x2_splat(std::f64::consts::LN_2);\n    let kf = f64x2_nearest(f64x2_mul(x, log2e));\n    let r = f64x2_sub(x, f64x2_mul(kf, ln2));\n    // Taylor exp(r), Horner\n    let mut p = f64x2_splat(1.0 / 720.0);\n    p = f64x2_add(f64x2_mul(p, r), f64x2_splat(1.0 / 120.0));\n    p = f64x2_add(f64x2_mul(p, r), f64x2_splat(1.0 / 24.0));\n    p = f64x2_add(f64x2_mul(p, r), f64x2_splat(1.0 / 6.0));\n    p = f64x2_add(f64x2_mul(p, r), f64x2_splat(0.5));\n    p = f64x2_add(f64x2_mul(p, r), f64x2_splat(1.0));\n    p = f64x2_add(f64x2_mul(p, r), f64x2_splat(1.0)); // exp(r)\n    // 2^k: k = kf truncated, (k+1023) << 52\n    let ki32 = i32x4_trunc_sat_f64x2_zero(kf); // low 2 lanes = k\n    let ki64 = i64x2_extend_low_i32x4(ki32);\n    let biased = i64x2_add(ki64, i64x2_splat(1023));\n    let pow2k = i64x2_shl(biased, 52); // reinterpreted as f64x2 bits\n    f64x2_mul(p, pow2k)\n}\n\n#[cfg(all(target_arch = \"wasm32\", target_feature = \"simd128\"))]\nfn silu_mul_wasm(a: &[f64], b: &[f64], out: &mut [f64]) {\n    use std::arch::wasm32::*;\n    let one = f64x2_splat(1.0);\n    let n = a.len();\n    let chunks = n / 2;\n    for c in 0..chunks {\n        let off = c * 2;\n        // SAFETY: off+2 <= n.\n        let x = unsafe { v128_load(a.as_ptr().add(off) as *const v128) };\n        let bv = unsafe { v128_load(b.as_ptr().add(off) as *const v128) };\n        let e = exp_pd_wasm(f64x2_neg(x));\n        let sig = f64x2_div(one, f64x2_add(one, e));\n        let r = f64x2_mul(f64x2_mul(x, sig), bv);\n        unsafe { v128_store(out.as_mut_ptr().add(off) as *mut v128, r) };\n    }\n    for i in (chunks * 2)..n {\n        let x = a[i];\n        let sig = 1.0 / (1.0 + (-x).exp());\n        out[i] = x * sig * b[i];\n    }\n}\n\n/// SIMD fast exp for ARM NEON (float64x2_t, 2-wide). Shared by silu/softmax/gelu\n/// on aarch64. NEON has native FMA and f64→i64 (vcvtq_s64_f64), so it's closer to\n/// the AVX version than wasm's.\n#[cfg(target_arch = \"aarch64\")]\n#[target_feature(enable = \"neon\")]\npub(crate) unsafe fn exp_pd_neon(\n    x: std::arch::aarch64::float64x2_t,\n) -> std::arch::aarch64::float64x2_t {\n    use std::arch::aarch64::*;\n    // Clamp to the bit-trick's valid range (see exp_pd): outside |x| ≲ 708 the\n    // `(k + 1023) << 52` shift wraps and returns garbage (softmax -1e9 mask).\n    let x = vmaxq_f64(vdupq_n_f64(-708.0), vminq_f64(x, vdupq_n_f64(708.0)));\n    let log2e = vdupq_n_f64(std::f64::consts::LOG2_E);\n    let ln2 = vdupq_n_f64(std::f64::consts::LN_2);\n    let kf = vrndnq_f64(vmulq_f64(x, log2e)); // round to nearest\n    let r = vsubq_f64(x, vmulq_f64(kf, ln2));\n    // Taylor exp(r), Horner via fma: vfmaq_f64(acc, p, r) = acc + p*r\n    let mut p = vdupq_n_f64(1.0 / 720.0);\n    p = vfmaq_f64(vdupq_n_f64(1.0 / 120.0), p, r);\n    p = vfmaq_f64(vdupq_n_f64(1.0 / 24.0), p, r);\n    p = vfmaq_f64(vdupq_n_f64(1.0 / 6.0), p, r);\n    p = vfmaq_f64(vdupq_n_f64(0.5), p, r);\n    p = vfmaq_f64(vdupq_n_f64(1.0), p, r);\n    p = vfmaq_f64(vdupq_n_f64(1.0), p, r); // exp(r)\n    // 2^k: k = round(kf) as i64, (k+1023) << 52, reinterpret as f64\n    let k = vcvtq_s64_f64(kf);\n    let biased = vaddq_s64(k, vdupq_n_s64(1023));\n    let pow2k = vshlq_n_s64::<52>(biased);\n    vmulq_f64(p, vreinterpretq_f64_s64(pow2k))\n}\n\n#[cfg(target_arch = \"aarch64\")]\n#[target_feature(enable = \"neon\")]\nunsafe fn silu_mul_neon(a: &[f64], b: &[f64], out: &mut [f64]) {\n    use std::arch::aarch64::*;\n    let one = vdupq_n_f64(1.0);\n    let n = a.len();\n    let chunks = n / 2;\n    for c in 0..chunks {\n        let off = c * 2;\n        let x = vld1q_f64(a.as_ptr().add(off));\n        let bv = vld1q_f64(b.as_ptr().add(off));\n        let e = exp_pd_neon(vnegq_f64(x));\n        let sig = vdivq_f64(one, vaddq_f64(one, e));\n        let r = vmulq_f64(vmulq_f64(x, sig), bv);\n        vst1q_f64(out.as_mut_ptr().add(off), r);\n    }\n    for i in (chunks * 2)..n {\n        let x = a[i];\n        let sig = 1.0 / (1.0 + (-x).exp());\n        out[i] = x * sig * b[i];\n    }\n}\n\n/// Per-target dispatch.\npub fn silu_mul(a: &[f64], b: &[f64], out: &mut [f64]) {\n    assert_eq!(a.len(), b.len());\n    assert_eq!(a.len(), out.len());\n    #[cfg(target_arch = \"x86_64\")]\n    {\n        if is_x86_feature_detected!(\"avx2\") && is_x86_feature_detected!(\"fma\") {\n            return unsafe { silu_mul_avx(a, b, out) };\n        }\n    }\n    #[cfg(target_arch = \"aarch64\")]\n    {\n        if std::arch::is_aarch64_feature_detected!(\"neon\") {\n            return unsafe { silu_mul_neon(a, b, out) };\n        }\n    }\n    #[cfg(all(target_arch = \"wasm32\", target_feature = \"simd128\"))]\n    {\n        return silu_mul_wasm(a, b, out);\n    }\n    silu_mul_naive(a, b, out);\n}\n\n\n}\npub mod softmax {\n//! softmax_rows — attention's core. Per row: `softmax(x)_i = exp(x_i - max) / Σ`.\n//! exp is the autovec wall; this reuses the SIMD fast-exp from silu. The reduce\n//! (max, sum) is order-dependent, so correctness is within-tolerance (exp approx\n//! + reassoc), and each row sums to 1 by construction.\n\n#[cfg(target_arch = \"x86_64\")]\nuse super::silu::exp_pd;\n\n/// Naive reference: scalar libm exp.\npub fn softmax_rows_naive(data: &[f64], rows: usize, cols: usize, out: &mut [f64]) {\n    for r in 0..rows {\n        let row = &data[r * cols..(r + 1) * cols];\n        let o = &mut out[r * cols..(r + 1) * cols];\n        let max = row.iter().copied().fold(f64::NEG_INFINITY, f64::max);\n        let mut sum = 0.0;\n        for j in 0..cols {\n            let e = (row[j] - max).exp();\n            o[j] = e;\n            sum += e;\n        }\n        let inv = 1.0 / sum;\n        for j in 0..cols {\n            o[j] *= inv;\n        }\n    }\n}\n\n/// SIMD one row: max (scalar), exp(x-max) (SIMD fast-exp) + lane-sum, then scale.\n#[cfg(target_arch = \"x86_64\")]\n#[target_feature(enable = \"avx2,fma\")]\nunsafe fn softmax_row_avx(row: &[f64], o: &mut [f64]) {\n    use std::arch::x86_64::*;\n    let cols = row.len();\n    let max = row.iter().copied().fold(f64::NEG_INFINITY, f64::max);\n    let vmax = _mm256_set1_pd(max);\n    let mut vsum = _mm256_setzero_pd();\n    let chunks = cols / 4;\n    for c in 0..chunks {\n        let x = _mm256_loadu_pd(row.as_ptr().add(c * 4));\n        let e = exp_pd(_mm256_sub_pd(x, vmax));\n        _mm256_storeu_pd(o.as_mut_ptr().add(c * 4), e);\n        vsum = _mm256_add_pd(vsum, e);\n    }\n    // horizontal sum of vsum\n    let hi = _mm256_extractf128_pd(vsum, 1);\n    let lo = _mm256_castpd256_pd128(vsum);\n    let s = _mm_add_pd(lo, hi);\n    let s = _mm_add_sd(s, _mm_unpackhi_pd(s, s));\n    let mut sum = _mm_cvtsd_f64(s);\n    for j in (chunks * 4)..cols {\n        let e = (row[j] - max).exp();\n        o[j] = e;\n        sum += e;\n    }\n    let inv = 1.0 / sum;\n    let vinv = _mm256_set1_pd(inv);\n    for c in 0..chunks {\n        let e = _mm256_loadu_pd(o.as_ptr().add(c * 4));\n        _mm256_storeu_pd(o.as_mut_ptr().add(c * 4), _mm256_mul_pd(e, vinv));\n    }\n    for j in (chunks * 4)..cols {\n        o[j] *= inv;\n    }\n}\n\n/// wasm simd128 one row: max (scalar), exp(x-max) f64x2 + lane-sum, scale.\n#[cfg(all(target_arch = \"wasm32\", target_feature = \"simd128\"))]\nfn softmax_row_wasm(row: &[f64], o: &mut [f64]) {\n    use super::silu::exp_pd_wasm;\n    use std::arch::wasm32::*;\n    let cols = row.len();\n    let max = row.iter().copied().fold(f64::NEG_INFINITY, f64::max);\n    let vmax = f64x2_splat(max);\n    let mut vsum = f64x2_splat(0.0);\n    let chunks = cols / 2;\n    for c in 0..chunks {\n        let x = unsafe { v128_load(row.as_ptr().add(c * 2) as *const v128) };\n        let e = exp_pd_wasm(f64x2_sub(x, vmax));\n        unsafe { v128_store(o.as_mut_ptr().add(c * 2) as *mut v128, e) };\n        vsum = f64x2_add(vsum, e);\n    }\n    let mut sum = f64x2_extract_lane::<0>(vsum) + f64x2_extract_lane::<1>(vsum);\n    for j in (chunks * 2)..cols {\n        let e = (row[j] - max).exp();\n        o[j] = e;\n        sum += e;\n    }\n    let inv = 1.0 / sum;\n    let vinv = f64x2_splat(inv);\n    for c in 0..chunks {\n        let e = unsafe { v128_load(o.as_ptr().add(c * 2) as *const v128) };\n        unsafe { v128_store(o.as_mut_ptr().add(c * 2) as *mut v128, f64x2_mul(e, vinv)) };\n    }\n    for j in (chunks * 2)..cols {\n        o[j] *= inv;\n    }\n}\n\n/// ARM NEON one row: max (scalar), exp(x-max) f64x2 + lane-sum, scale.\n#[cfg(target_arch = \"aarch64\")]\n#[target_feature(enable = \"neon\")]\nunsafe fn softmax_row_neon(row: &[f64], o: &mut [f64]) {\n    use super::silu::exp_pd_neon;\n    use std::arch::aarch64::*;\n    let cols = row.len();\n    let max = row.iter().copied().fold(f64::NEG_INFINITY, f64::max);\n    let vmax = vdupq_n_f64(max);\n    let mut vsum = vdupq_n_f64(0.0);\n    let chunks = cols / 2;\n    for c in 0..chunks {\n        let x = vld1q_f64(row.as_ptr().add(c * 2));\n        let e = exp_pd_neon(vsubq_f64(x, vmax));\n        vst1q_f64(o.as_mut_ptr().add(c * 2), e);\n        vsum = vaddq_f64(vsum, e);\n    }\n    let mut sum = vgetq_lane_f64::<0>(vsum) + vgetq_lane_f64::<1>(vsum);\n    for j in (chunks * 2)..cols {\n        let e = (row[j] - max).exp();\n        o[j] = e;\n        sum += e;\n    }\n    let inv = 1.0 / sum;\n    let vinv = vdupq_n_f64(inv);\n    for c in 0..chunks {\n        let e = vld1q_f64(o.as_ptr().add(c * 2));\n        vst1q_f64(o.as_mut_ptr().add(c * 2), vmulq_f64(e, vinv));\n    }\n    for j in (chunks * 2)..cols {\n        o[j] *= inv;\n    }\n}\n\n/// Per-target dispatch.\npub fn softmax_rows(data: &[f64], rows: usize, cols: usize, out: &mut [f64]) {\n    #[cfg(target_arch = \"x86_64\")]\n    {\n        if is_x86_feature_detected!(\"avx2\") && is_x86_feature_detected!(\"fma\") {\n            for r in 0..rows {\n                unsafe {\n                    softmax_row_avx(&data[r * cols..(r + 1) * cols], &mut out[r * cols..(r + 1) * cols]);\n                }\n            }\n            return;\n        }\n    }\n    #[cfg(target_arch = \"aarch64\")]\n    {\n        if std::arch::is_aarch64_feature_detected!(\"neon\") {\n            for r in 0..rows {\n                unsafe {\n                    softmax_row_neon(&data[r * cols..(r + 1) * cols], &mut out[r * cols..(r + 1) * cols]);\n                }\n            }\n            return;\n        }\n    }\n    #[cfg(all(target_arch = \"wasm32\", target_feature = \"simd128\"))]\n    {\n        for r in 0..rows {\n            softmax_row_wasm(&data[r * cols..(r + 1) * cols], &mut out[r * cols..(r + 1) * cols]);\n        }\n        return;\n    }\n    softmax_rows_naive(data, rows, cols, out);\n}\n\n\n}\npub mod transpose {\n//! 8x8 f32 transpose — Exo-style: algorithm (what) and schedule (how) separated.\n//!\n//! - `transpose_8x8_naive` is the **algorithm**: the spec, `out[j][i] = in[i][j]`.\n//! - The **schedule** is an explicit composition of named passes (load → unpack\n//!   → shuffle → permute → store), not one hand-written SIMD blob. Each pass is\n//!   an independent transform; composing them *is* the schedule. To change how\n//!   the transpose runs, recompose the passes — the algorithm above is untouched.\n//! - **Equivalence** (Exo's program-equivalence guarantee) is pinned by the\n//!   differential test: every schedule must be bitwise-exact to the naive\n//!   algorithm. Static proof (Lean) is the optional stronger backstop; the\n//!   differential test is the everyday guarantee.\n\n/// Algorithm: `out[j*8 + i] = in[i*8 + j]` (the spec every schedule must match).\npub fn transpose_8x8_naive(input: &[f32; 64]) -> [f32; 64] {\n    let mut out = [0.0f32; 64];\n    for i in 0..8 {\n        for j in 0..8 {\n            out[j * 8 + i] = input[i * 8 + j];\n        }\n    }\n    out\n}\n\n/// Public entry. Per-target schedule (AVX on x86, simd128 on wasm), naive else.\npub fn transpose_8x8(input: &[f32; 64]) -> [f32; 64] {\n    #[cfg(target_arch = \"x86_64\")]\n    {\n        if is_x86_feature_detected!(\"avx\") {\n            // SAFETY: guarded by the runtime feature check.\n            return unsafe { transpose_8x8_avx(input) };\n        }\n    }\n    #[cfg(all(target_arch = \"wasm32\", target_feature = \"simd128\"))]\n    {\n        return transpose_8x8_simd128(input);\n    }\n    #[allow(unreachable_code)]\n    transpose_8x8_naive(input)\n}\n\n// ============== schedule: wasm simd128 (128-bit = f32x4) ==============\n// 8x8 decomposes into four 4x4 blocks; each block transposed by a 4x4 shuffle\n// pass, then the off-diagonal blocks swap places. The 4x4 pass is the unit;\n// the schedule composes four of them + the block swap. Bitwise-exact (no reassoc\n// — it's pure data movement).\n\n/// pass: transpose a 4x4 block held in four f32x4 rows.\n#[cfg(all(target_arch = \"wasm32\", target_feature = \"simd128\"))]\n#[inline(always)]\nfn transpose_4x4(\n    r0: std::arch::wasm32::v128,\n    r1: std::arch::wasm32::v128,\n    r2: std::arch::wasm32::v128,\n    r3: std::arch::wasm32::v128,\n) -> [std::arch::wasm32::v128; 4] {\n    use std::arch::wasm32::*;\n    let t0 = i32x4_shuffle::<0, 4, 1, 5>(r0, r1);\n    let t1 = i32x4_shuffle::<2, 6, 3, 7>(r0, r1);\n    let t2 = i32x4_shuffle::<0, 4, 1, 5>(r2, r3);\n    let t3 = i32x4_shuffle::<2, 6, 3, 7>(r2, r3);\n    [\n        i32x4_shuffle::<0, 1, 4, 5>(t0, t2),\n        i32x4_shuffle::<2, 3, 6, 7>(t0, t2),\n        i32x4_shuffle::<0, 1, 4, 5>(t1, t3),\n        i32x4_shuffle::<2, 3, 6, 7>(t1, t3),\n    ]\n}\n\n#[cfg(all(target_arch = \"wasm32\", target_feature = \"simd128\"))]\nfn transpose_8x8_simd128(input: &[f32; 64]) -> [f32; 64] {\n    use std::arch::wasm32::*;\n    let p = input.as_ptr();\n    // each row = left half (cols 0-3) + right half (cols 4-7)\n    // SAFETY: 64 f32 in, all offsets < 64.\n    let ld = |off: usize| unsafe { v128_load(p.add(off) as *const v128) };\n    let (l0, r0) = (ld(0), ld(4));\n    let (l1, r1) = (ld(8), ld(12));\n    let (l2, r2) = (ld(16), ld(20));\n    let (l3, r3) = (ld(24), ld(28));\n    let (l4, r4) = (ld(32), ld(36));\n    let (l5, r5) = (ld(40), ld(44));\n    let (l6, r6) = (ld(48), ld(52));\n    let (l7, r7) = (ld(56), ld(60));\n    let a = transpose_4x4(l0, l1, l2, l3); // top-left  → out rows 0-3, left\n    let b = transpose_4x4(l4, l5, l6, l7); // bot-left  → out rows 0-3, right\n    let c = transpose_4x4(r0, r1, r2, r3); // top-right → out rows 4-7, left\n    let d = transpose_4x4(r4, r5, r6, r7); // bot-right → out rows 4-7, right\n    let mut out = [0.0f32; 64];\n    let q = out.as_mut_ptr();\n    let st = |off: usize, v: v128| unsafe { v128_store(q.add(off) as *mut v128, v) };\n    for j in 0..4 {\n        st(j * 8, a[j]);\n        st(j * 8 + 4, b[j]);\n        st((j + 4) * 8, c[j]);\n        st((j + 4) * 8 + 4, d[j]);\n    }\n    out\n}\n\n// ===================== schedule: AVX 3-pass shuffle network =====================\n// The \"how\", separated from the algorithm. Each pass is a named, independent\n// transform on the 8 row-vectors. The schedule is their composition.\n\n#[cfg(target_arch = \"x86_64\")]\nmod avx {\n    use std::arch::x86_64::*;\n\n    #[inline(always)]\n    pub unsafe fn load_rows(input: &[f32; 64]) -> [__m256; 8] {\n        let p = input.as_ptr();\n        [\n            _mm256_loadu_ps(p),\n            _mm256_loadu_ps(p.add(8)),\n            _mm256_loadu_ps(p.add(16)),\n            _mm256_loadu_ps(p.add(24)),\n            _mm256_loadu_ps(p.add(32)),\n            _mm256_loadu_ps(p.add(40)),\n            _mm256_loadu_ps(p.add(48)),\n            _mm256_loadu_ps(p.add(56)),\n        ]\n    }\n\n    /// pass 1: unpack adjacent rows within each 128-bit lane.\n    #[inline(always)]\n    pub unsafe fn pass_unpack(r: [__m256; 8]) -> [__m256; 8] {\n        [\n            _mm256_unpacklo_ps(r[0], r[1]),\n            _mm256_unpackhi_ps(r[0], r[1]),\n            _mm256_unpacklo_ps(r[2], r[3]),\n            _mm256_unpackhi_ps(r[2], r[3]),\n            _mm256_unpacklo_ps(r[4], r[5]),\n            _mm256_unpackhi_ps(r[4], r[5]),\n            _mm256_unpacklo_ps(r[6], r[7]),\n            _mm256_unpackhi_ps(r[6], r[7]),\n        ]\n    }\n\n    /// pass 2: shuffle 64-bit groups across the unpacked pairs.\n    #[inline(always)]\n    pub unsafe fn pass_shuffle(t: [__m256; 8]) -> [__m256; 8] {\n        [\n            _mm256_shuffle_ps(t[0], t[2], 0x44),\n            _mm256_shuffle_ps(t[0], t[2], 0xEE),\n            _mm256_shuffle_ps(t[1], t[3], 0x44),\n            _mm256_shuffle_ps(t[1], t[3], 0xEE),\n            _mm256_shuffle_ps(t[4], t[6], 0x44),\n            _mm256_shuffle_ps(t[4], t[6], 0xEE),\n            _mm256_shuffle_ps(t[5], t[7], 0x44),\n            _mm256_shuffle_ps(t[5], t[7], 0xEE),\n        ]\n    }\n\n    /// pass 3: permute 128-bit lanes to finish the transpose.\n    #[inline(always)]\n    pub unsafe fn pass_permute(s: [__m256; 8]) -> [__m256; 8] {\n        [\n            _mm256_permute2f128_ps(s[0], s[4], 0x20),\n            _mm256_permute2f128_ps(s[1], s[5], 0x20),\n            _mm256_permute2f128_ps(s[2], s[6], 0x20),\n            _mm256_permute2f128_ps(s[3], s[7], 0x20),\n            _mm256_permute2f128_ps(s[0], s[4], 0x31),\n            _mm256_permute2f128_ps(s[1], s[5], 0x31),\n            _mm256_permute2f128_ps(s[2], s[6], 0x31),\n            _mm256_permute2f128_ps(s[3], s[7], 0x31),\n        ]\n    }\n\n    #[inline(always)]\n    pub unsafe fn store_rows(rows: [__m256; 8]) -> [f32; 64] {\n        let mut out = [0.0f32; 64];\n        let q = out.as_mut_ptr();\n        _mm256_storeu_ps(q, rows[0]);\n        _mm256_storeu_ps(q.add(8), rows[1]);\n        _mm256_storeu_ps(q.add(16), rows[2]);\n        _mm256_storeu_ps(q.add(24), rows[3]);\n        _mm256_storeu_ps(q.add(32), rows[4]);\n        _mm256_storeu_ps(q.add(40), rows[5]);\n        _mm256_storeu_ps(q.add(48), rows[6]);\n        _mm256_storeu_ps(q.add(56), rows[7]);\n        out\n    }\n}\n\n/// The AVX schedule: load → unpack → shuffle → permute → store, composed.\n/// This single line *is* the schedule — recompose the passes to change it.\n#[cfg(target_arch = \"x86_64\")]\n#[target_feature(enable = \"avx\")]\nunsafe fn transpose_8x8_avx(input: &[f32; 64]) -> [f32; 64] {\n    use avx::*;\n    store_rows(pass_permute(pass_shuffle(pass_unpack(load_rows(input)))))\n}\n\n/// Transpose an arbitrary `rows × cols` row-major f32 matrix into `out`\n/// (`cols × rows`). This is what `almide_rt` actually needs — Almide's matrices\n/// aren't 8x8. Full 8x8 tiles go through the SIMD kernel; the ragged right/bottom\n/// edges are scalar. Bitwise-exact (data movement, no reassoc).\npub fn transpose_matrix(input: &[f32], rows: usize, cols: usize, out: &mut [f32]) {\n    assert_eq!(input.len(), rows * cols);\n    assert_eq!(out.len(), rows * cols);\n    let rt = rows / 8 * 8; // tiled extent (multiple of 8)\n    let ct = cols / 8 * 8;\n    let mut tile = [0.0f32; 64];\n    let mut ti = 0;\n    while ti < rt {\n        let mut tj = 0;\n        while tj < ct {\n            for r in 0..8 {\n                let base = (ti + r) * cols + tj;\n                tile[r * 8..r * 8 + 8].copy_from_slice(&input[base..base + 8]);\n            }\n            let t = transpose_8x8(&tile);\n            for r in 0..8 {\n                let base = (tj + r) * rows + ti;\n                out[base..base + 8].copy_from_slice(&t[r * 8..r * 8 + 8]);\n            }\n            tj += 8;\n        }\n        ti += 8;\n    }\n    // ragged edges: any (i, j) not covered by a full tile\n    for i in 0..rows {\n        for j in 0..cols {\n            if i >= rt || j >= ct {\n                out[j * rows + i] = input[i * cols + j];\n            }\n        }\n    }\n}\n\n\n}\npub mod transpose_f64 {\n//! f64 transpose — Almide's matrices are f64, and transpose is data movement, so\n//! an f64 kernel keeps the values exact (no f32 rounding). AVX uses f64x4\n//! (256-bit), so 8x8 decomposes into four 4x4 blocks (same shape as the wasm\n//! f32 path). Bitwise-exact.\n\n/// Algorithm: `out[j*8+i] = in[i*8+j]` in f64.\npub fn transpose_8x8_f64_naive(input: &[f64; 64]) -> [f64; 64] {\n    let mut out = [0.0f64; 64];\n    for i in 0..8 {\n        for j in 0..8 {\n            out[j * 8 + i] = input[i * 8 + j];\n        }\n    }\n    out\n}\n\n/// Public entry: AVX f64x4 when available, naive otherwise.\npub fn transpose_8x8_f64(input: &[f64; 64]) -> [f64; 64] {\n    #[cfg(target_arch = \"x86_64\")]\n    {\n        if is_x86_feature_detected!(\"avx\") {\n            // SAFETY: guarded by the runtime feature check.\n            return unsafe { transpose_8x8_f64_avx(input) };\n        }\n    }\n    transpose_8x8_f64_naive(input)\n}\n\n#[cfg(target_arch = \"x86_64\")]\n#[inline(always)]\nunsafe fn transpose_4x4_f64(\n    r0: std::arch::x86_64::__m256d,\n    r1: std::arch::x86_64::__m256d,\n    r2: std::arch::x86_64::__m256d,\n    r3: std::arch::x86_64::__m256d,\n) -> [std::arch::x86_64::__m256d; 4] {\n    use std::arch::x86_64::*;\n    let t0 = _mm256_unpacklo_pd(r0, r1);\n    let t1 = _mm256_unpackhi_pd(r0, r1);\n    let t2 = _mm256_unpacklo_pd(r2, r3);\n    let t3 = _mm256_unpackhi_pd(r2, r3);\n    [\n        _mm256_permute2f128_pd(t0, t2, 0x20),\n        _mm256_permute2f128_pd(t1, t3, 0x20),\n        _mm256_permute2f128_pd(t0, t2, 0x31),\n        _mm256_permute2f128_pd(t1, t3, 0x31),\n    ]\n}\n\n#[cfg(target_arch = \"x86_64\")]\n#[target_feature(enable = \"avx\")]\nunsafe fn transpose_8x8_f64_avx(input: &[f64; 64]) -> [f64; 64] {\n    use std::arch::x86_64::*;\n    let p = input.as_ptr();\n    let ld = |off: usize| _mm256_loadu_pd(p.add(off));\n    // each row = left (cols 0-3) + right (cols 4-7)\n    let (l0, r0) = (ld(0), ld(4));\n    let (l1, r1) = (ld(8), ld(12));\n    let (l2, r2) = (ld(16), ld(20));\n    let (l3, r3) = (ld(24), ld(28));\n    let (l4, r4) = (ld(32), ld(36));\n    let (l5, r5) = (ld(40), ld(44));\n    let (l6, r6) = (ld(48), ld(52));\n    let (l7, r7) = (ld(56), ld(60));\n    let a = transpose_4x4_f64(l0, l1, l2, l3); // top-left  → rows 0-3, left\n    let b = transpose_4x4_f64(l4, l5, l6, l7); // bot-left  → rows 0-3, right\n    let c = transpose_4x4_f64(r0, r1, r2, r3); // top-right → rows 4-7, left\n    let d = transpose_4x4_f64(r4, r5, r6, r7); // bot-right → rows 4-7, right\n    let mut out = [0.0f64; 64];\n    let q = out.as_mut_ptr();\n    for j in 0..4 {\n        _mm256_storeu_pd(q.add(j * 8), a[j]);\n        _mm256_storeu_pd(q.add(j * 8 + 4), b[j]);\n        _mm256_storeu_pd(q.add((j + 4) * 8), c[j]);\n        _mm256_storeu_pd(q.add((j + 4) * 8 + 4), d[j]);\n    }\n    out\n}\n\n/// Arbitrary-size f64 transpose: 8x8 tiles through the SIMD kernel, scalar edges.\npub fn transpose_matrix_f64(input: &[f64], rows: usize, cols: usize, out: &mut [f64]) {\n    assert_eq!(input.len(), rows * cols);\n    assert_eq!(out.len(), rows * cols);\n    let rt = rows / 8 * 8;\n    let ct = cols / 8 * 8;\n    let mut tile = [0.0f64; 64];\n    let mut ti = 0;\n    while ti < rt {\n        let mut tj = 0;\n        while tj < ct {\n            for r in 0..8 {\n                let base = (ti + r) * cols + tj;\n                tile[r * 8..r * 8 + 8].copy_from_slice(&input[base..base + 8]);\n            }\n            let t = transpose_8x8_f64(&tile);\n            for r in 0..8 {\n                let base = (tj + r) * rows + ti;\n                out[base..base + 8].copy_from_slice(&t[r * 8..r * 8 + 8]);\n            }\n            tj += 8;\n        }\n        ti += 8;\n    }\n    for i in 0..rows {\n        for j in 0..cols {\n            if i >= rt || j >= ct {\n                out[j * rows + i] = input[i * cols + j];\n            }\n        }\n    }\n}\n\n\n}\n}\n";
